sys_script.script:
(function executeRule(current, previous /*null when async*/) {

    // --- HELPER FUNCTIONS ---
    function isDraftOrEmpty(rawVal, displayVal) {
        var raw = (rawVal || '').toString().toLowerCase().trim();
        var display = (displayVal || '').toString().toLowerCase().trim();
        if (!raw || raw === '0' || raw === 'undefined' || raw === 'null') return true;
        if (raw.indexOf('draft') > -1 || display.indexOf('draft') > -1) return true;
        return false;
    }

    function normalise(str) {
        return (str || '').toString().toLowerCase().replace(/[^a-z0-9]/g, '');
    }

    var rawVal     = current.target_license.toString();
    var displayVal = current.target_license.getDisplayValue();
    var isDraft    = isDraftOrEmpty(rawVal, displayVal);
    var licenseSearch = normalise(rawVal) + normalise(displayVal);

    // ==========================================================================
    // STEP 1: LIVE PRICING CALCULATOR (Sequential Logic)
    // ==========================================================================
    var livePrice = 0;

    if (!isDraft) {
        if (licenseSearch.indexOf('itsmenterprise') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_itsm_enterprise', '1500')); }
        else if (licenseSearch.indexOf('itsmstandard') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_itsm_standard', '1000')); }
        else if (licenseSearch.indexOf('itsmprofessional') > -1 || licenseSearch.indexOf('itsmpro') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_itsm_pro', '1200')); }
        else if (licenseSearch.indexOf('itsmadmin') > -1 || licenseSearch.indexOf('itsmdeveloper') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_itsm_admin', '1200')); }

        else if (licenseSearch.indexOf('hrsdenterprise') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_hrsd_enterprise', '1300')); }
        else if (licenseSearch.indexOf('hrsdstandard') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_hrsd_standard', '800')); }
        else if (licenseSearch.indexOf('hrsdprofessional') > -1 || licenseSearch.indexOf('hrsdpro') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_hrsd_pro', '1000')); }
        else if (licenseSearch.indexOf('hrsdadmin') > -1 || licenseSearch.indexOf('hradmin') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_hrsd_admin', '1000')); }
        else if (licenseSearch.indexOf('hrsder') > -1 || licenseSearch.indexOf('employeerelations') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_hrsd_er', '1100')); }

        else if (licenseSearch.indexOf('csmenterprise') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_csm_enterprise', '1400')); }
        else if (licenseSearch.indexOf('csmstandard') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_csm_standard', '900')); }
        else if (licenseSearch.indexOf('csmprofessional') > -1 || licenseSearch.indexOf('csmpro') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_csm_pro', '1100')); }
        else if (licenseSearch.indexOf('csmadmin') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_csm_admin', '1100')); }
        else if (licenseSearch.indexOf('csmcontributor') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_csm_contributor', '500')); }

        else if (licenseSearch.indexOf('spmenterprise') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_spm_enterprise', '1600')); }
        else if (licenseSearch.indexOf('spmstandard') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_spm_standard', '1100')); }
        else if (licenseSearch.indexOf('spmprofessional') > -1 || licenseSearch.indexOf('spmpro') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_spm_pro', '1300')); }
        else if (licenseSearch.indexOf('spmadmin') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_spm_admin', '1300')); }
        else if (licenseSearch.indexOf('spmagile') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_spm_agile', '400')); }

        else if (licenseSearch.indexOf('approveruser') > -1 || licenseSearch.indexOf('legacyapprover') > -1) { livePrice = parseInt(gs.getProperty('x_1977323_smartlic.cost_approver_user', '100')); }
    }

    if (isNaN(livePrice)) { livePrice = 0; }

    // ==========================================================================
    // STEP 2: STATUS OVERRIDES (Manual & VTB Interceptor)
    // ==========================================================================
    var newStatus = current.review_status.toString();
    var statusChangedToRevoked = current.review_status.changes() && (newStatus === 'manually_revoked' || newStatus === 'auto_revoked');

    if (statusChangedToRevoked) {
        var moneyToFreeze = livePrice || previous.getValue('amount') || current.getValue('amount') || 0;
        current.setValue('cost_saved', moneyToFreeze);
        current.setValue('target_license', 'Draft');
        current.setValue('amount', 0);
        isDraft = true; 
    }

    // ==========================================================================
    // STEP 3: STRICT INACTIVITY ENGINE (Auto-Correction Logic)
    // Runs on EVERY save — no early return — overwrites any wrong manual entry
    // ==========================================================================
    if (isDraft) {
        current.setValue('amount', 0);
        current.setValue('ai_confidence_score', 0);

        if (newStatus === 'manually_revoked') {
            current.setValue('ai_justification', 'Manual Override: License Revoked.');
        } else if (newStatus === 'auto_revoked') {
            current.setValue('ai_justification', 'AI Assessment: Inactivity threshold reached.');
        } else {
            current.setValue('ai_justification', 'Waiting for assignment...');
        }

    } else {
        current.setValue('amount', livePrice);

        if (current.target_license.changes()) {
            current.setValue('cost_saved', 0);
        }

        if (!current.isNewRecord() && current.target_license.changes() && gs.isInteractive()) {
            current.setValue('days_inactive', 0);
        }

        var inactivityThreshold = parseInt(gs.getProperty('x_1977323_smartlic.inactivity_days', '90'));
        var daysInactive = parseInt(current.days_inactive.toString()) || 0;

        // --- AUTHORITATIVE AUTO-CORRECTION ---
        // Priority 1: Auto-revoke threshold — cannot be overridden by anyone
        if (daysInactive >= inactivityThreshold) {
            current.setValue('ai_confidence_score', 95);
            current.setValue('ai_justification',    'AI Assessment: Inactivity threshold reached.');
            current.setValue('review_status',       'auto_revoked');
            current.setValue('cost_saved',          livePrice);
            current.setValue('target_license',      'Draft');
            current.setValue('amount',              0);

        // Priority 2: Active / newly assigned (0–30 days)
        } else if (daysInactive >= 0 && daysInactive <= 30) {

            // FIX: "Retained" is the ONLY manual choice respected in this range
            if (current.review_status.changes() && gs.isInteractive() && newStatus === 'retained') {
                current.setValue('ai_justification', 'Manual Override: Manager retained license.');
                // NO return — amount and score set above are preserved
            } else {
                // Any other manually entered status gets corrected automatically
                current.setValue('ai_confidence_score', 10);
                current.setValue('review_status',       'newly_assigned');
                current.setValue('ai_justification',    'AI Assessment: User is active or newly assigned.');
            }

        // Priority 3: Grace period (31–89 days)
        } else {

            // FIX: "Retained" is the ONLY manual choice respected in this range
            if (current.review_status.changes() && gs.isInteractive() && newStatus === 'retained') {
                current.setValue('ai_justification', 'Manual Override: Manager retained license.');
                // NO return — amount and score set above are preserved
            } else {
                // Any other manually entered status gets corrected automatically
                current.setValue('ai_confidence_score', 40);
                current.setValue('review_status',       'pending_review');
                current.setValue('ai_justification',    'AI Assessment: User is currently within the grace period.');
            }
        }
    }

})(current, previous);
